1→package api
     2→
     3→import (
     4→	"net/http"
     5→	"time"
     6→
     7→	"golang.org/x/time/rate"
     8→
     9→	"github.com/grafana/grafana/pkg/api/frontendlogging"
    10→	"github.com/grafana/grafana/pkg/infra/log"
    11→	"github.com/grafana/grafana/pkg/web"
    12→)
    13→
    14→var frontendLogger = log.New("frontend")
    15→
    16→type frontendLogMessageHandler func(hs *HTTPServer, c *web.Context)
    17→
    18→const grafanaJavascriptAgentEndpointPath = "/log-grafana-javascript-agent"
    19→
    20→func GrafanaJavascriptAgentLogMessageHandler(store *frontendlogging.SourceMapStore) frontendLogMessageHandler {
    21→	return func(hs *HTTPServer, c *web.Context) {
    22→		event := frontendlogging.FrontendGrafanaJavascriptAgentEvent{}
    23→		if err := web.Bind(c.Req, &event); err != nil {
    24→			c.Resp.WriteHeader(http.StatusBadRequest)
    25→			_, err = c.Resp.Write([]byte("bad request data"))
    26→			if err != nil {
    27→				hs.log.Error("could not write to response", "err", err)
    28→			}
    29→		}
    30→
    31→		// Meta object is standard across event types, adding it globally.
    32→
    33→		if len(event.Logs) > 0 {
    34→			for _, logEntry := range event.Logs {
    35→				var ctx = frontendlogging.CtxVector{}
    36→				ctx = event.AddMetaToContext(ctx)
    37→				ctx = append(ctx, "kind", "log", "original_timestamp", logEntry.Timestamp)
    38→
    39→				for k, v := range frontendlogging.KeyValToInterfaceMap(logEntry.KeyValContext()) {
    40→					ctx = append(ctx, k, v)
    41→				}
    42→				switch logEntry.LogLevel {
    43→				case frontendlogging.LogLevelDebug, frontendlogging.LogLevelTrace:
    44→					{
    45→						ctx = append(ctx, "original_log_level", logEntry.LogLevel)
    46→						frontendLogger.Debug(logEntry.Message, ctx...)
    47→					}
    48→				case frontendlogging.LogLevelError:
    49→					{
    50→						ctx = append(ctx, "original_log_level", logEntry.LogLevel)
    51→						frontendLogger.Error(logEntry.Message, ctx...)
    52→					}
    53→				case frontendlogging.LogLevelWarning:
    54→					{
    55→						ctx = append(ctx, "original_log_level", logEntry.LogLevel)
    56→						frontendLogger.Warn(logEntry.Message, ctx...)
    57→					}
    58→				default:
    59→					{
    60→						ctx = append(ctx, "original_log_level", logEntry.LogLevel)
    61→						frontendLogger.Info(logEntry.Message, ctx...)
    62→					}
    63→				}
    64→			}
    65→		}
    66→
    67→		if len(event.Measurements) > 0 {
    68→			for _, measurementEntry := range event.Measurements {
    69→				for measurementName, measurementValue := range measurementEntry.Values {
    70→					var ctx = frontendlogging.CtxVector{}
    71→					ctx = event.AddMetaToContext(ctx)
    72→					ctx = append(ctx, measurementName, measurementValue)
    73→					ctx = append(ctx, "kind", "measurement", "original_timestamp", measurementEntry.Timestamp)
    74→					frontendLogger.Info("Measurement: "+measurementEntry.Type, ctx...)
    75→				}
    76→			}
    77→		}
    78→		if len(event.Exceptions) > 0 {
    79→			for _, exception := range event.Exceptions {
    80→				var ctx = frontendlogging.CtxVector{}
    81→				ctx = event.AddMetaToContext(ctx)
    82→				exception := exception
    83→				transformedException := frontendlogging.TransformException(c.Req.Context(), &exception, store)
    84→				ctx = append(ctx, "kind", "exception", "type", transformedException.Type, "value", transformedException.Value, "stacktrace", transformedException.String())
    85→				ctx = append(ctx, "original_timestamp", exception.Timestamp)
    86→				frontendLogger.Error(exception.Message(), ctx...)
    87→			}
    88→		}
    89→		c.Resp.WriteHeader(http.StatusAccepted)
    90→		_, err := c.Resp.Write([]byte("OK"))
    91→		if err != nil {
    92→			hs.log.Error("could not write to response", "err", err)
    93→		}
    94→	}
    95→}
    96→
    97→// setupFrontendLogHandlers will set up handlers for logs incoming from frontend.
    98→// handlers are setup even if frontend logging is disabled, but in this case do nothing
    99→// this is to avoid reporting errors in case config was changes but there are browser
   100→// sessions still open with older config
   101→func (hs *HTTPServer) frontendLogEndpoints() web.Handler {
   102→	if !(hs.Cfg.GrafanaJavascriptAgent.Enabled) {
   103→		return func(ctx *web.Context) {
   104→			if ctx.Req.Method == http.MethodPost && ctx.Req.URL.Path == grafanaJavascriptAgentEndpointPath {
   105→				ctx.Resp.WriteHeader(http.StatusAccepted)
   106→				_, err := ctx.Resp.Write([]byte("OK"))
   107→				if err != nil {
   108→					hs.log.Error("could not write to response", "err", err)
   109→				}
   110→			}
   111→		}
   112→	}
   113→
   114→	sourceMapStore := frontendlogging.NewSourceMapStore(hs.Cfg, hs.pluginStaticRouteResolver, frontendlogging.ReadSourceMapFromFS)
   115→	rateLimiter := rate.NewLimiter(rate.Limit(hs.Cfg.GrafanaJavascriptAgent.EndpointRPS), hs.Cfg.GrafanaJavascriptAgent.EndpointBurst)
   116→	handler := GrafanaJavascriptAgentLogMessageHandler(sourceMapStore)
   117→
   118→	return func(ctx *web.Context) {
   119→		if ctx.Req.Method == http.MethodPost && ctx.Req.URL.Path == grafanaJavascriptAgentEndpointPath {
   120→			if !rateLimiter.AllowN(time.Now(), 1) {
   121→				ctx.Resp.WriteHeader(http.StatusTooManyRequests)
   122→				return
   123→			}
   124→			handler(hs, ctx)
   125→		}
   126→	}
   127→}
